actions.script:
// ec.l10n.localize() does NOT expand ${} - always run the result through expand(). def loc = ec.context.userLocale ? new Locale(ec.context.userLocale) : ec.user.locale String app = ec.context.application ?: 'Admin'
def msg = { String key -> ec.resource.expand(ec.l10n.localize(key, loc), '') } def appMsg = { String base -> String key = base + app String raw = ec.l10n.localize(key, loc) if (raw == key) raw = ec.l10n.localize(base + 'Default', loc) return ec.resource.expand(raw, '') }
def named = { String s -> s && s ==~ /(?s).*\p{L}.*/ } String fn = named(ec.context.firstName) ? ec.context.firstName.trim() : '' String ln = named(ec.context.lastName) ? ec.context.lastName.trim() : ''
ec.context.application = app ec.context.userName = [fn, ln].findAll({ it }).join(' ')
greeting = ec.context.userName ? msg('GrowerpEmailWelcomeGreeting') : msg('GrowerpEmailWelcomeGreetingNoName') testNote = msg('GrowerpEmailWelcomeTestNote') intro = appMsg('GrowerpEmailWelcomeIntro') firstStep = appMsg('GrowerpEmailWelcomeFirstStep') supportInfo = msg('GrowerpEmailWelcomeSupportInfo') passwordInfo = msg('GrowerpEmailWelcomePasswordInfo') tipsInfo = msg('GrowerpEmailWelcomeTipsInfo') regards = msg('GrowerpEmailWelcomeRegards') team = msg('GrowerpEmailWelcomeTeam')
